const segments = ($input.first().json.timestamped_transcription) ?? [];
const out = [];

const mergedSentence = segments
  .map(seg => typeof seg?.sentence === 'string' ? seg.sentence.trim() : '')
  .filter(Boolean)
  .join(' ')
  .replace(/\s+([,.!?;:])/g, '$1') // tidy spacing before punctuation
  .replace(/\s{2,}/g, ' ')         // remove double spaces
  .trim();

out.push({
  json: {
    mergedSentence,
    segmentCount: segments.length
  }
});

return out;
